from functools import lru_cache
import math
@lru_cache(maxsize=None)
def rad(n):
    r = 1
    p = 2
    while p * p <= n:
        if n % p == 0:
            r *= p
            while n % p == 0:
                n //= p
        p += 1 if p == 2 else 2
    if n > 1:
        r *= n
    return r
def is_fertile(c):
    pairs = set()
    for a in range(1, c//2 + 1):
        b = c - a
        if math.gcd(a, b) != 1:
            continue
        if rad(a) * rad(b) * rad(c) < c:
            pairs.add((a, b))
            if len(pairs) == 2:
                return True
    return False
res = [c for c in range(2, 10000) if is_fertile(c)]
